SELECT 


 ORDER BY p.rprt_yr DESC, p.emp_ver DESC, p.frst_reg_dt DESC
 LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
  FROM emp.tn_emp_plan p
 WHERE p.oprtr_id   = #{oprtrId}
   AND p.emp_st_cd  IN ('DRAFT', 'SBMTD', 'RVWNG', 'RCMDD')
   AND p.emp_plan_id != #{excludeId}
   AND NOW() BETWEEN p.use_bgng_dt AND p.use_end_dt

SELECT MAX(CAST(SPLIT_PART(emp_ver, '.', 1) AS INTEGER)) || '.0'
  FROM emp.tn_emp_plan
 WHERE oprtr_id = #{oprtrId}

mapper.update:
UPDATE emp.tn_emp_plan
   SET emp_st_cd        = #{empStCd},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE emp_plan_id = #{empPlanId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE emp.tn_emp_plan
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE emp_plan_id = #{empPlanId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
